inject.text:
trustedOrigins: (process.env.CORS_ORIGIN ?? "http://localhost:5001").split(",").map((origin) => origin.trim()),
  databaseHooks: {
    user: {
      create: {
        before: async (user) => ({
          data: {
            ...user,
            role: (process.env.ADMIN_EMAILS ?? "")
              .split(",")
              .map((email) => email.trim().toLowerCase())
              .includes(user.email.toLowerCase())
              ? "admin"
              : "user",
          },
        }),
      },
    },
  },
